// // This module implements a 4-bit DRAM cell with read and write capabilities.
// It has a data input (4 bits), a data output (4 bits), a read enable signal,
// a write enable signal, and a clock signal. The DRAM cell should remember
// the written data until it is overwritten. The read operation should output
// the stored data when the read enable signal is low and the write operation
// should store the input data when the write enable signal is low.
module dram_cell (
    input wire clk,
    input wire [3:0] data_in,
    input wire read_enable,
    input wire write_enable,
    output reg [3:0] data_out
);
    reg [3:0] memory;

    always @(posedge clk) begin
        if (write_enable) begin
            memory <= data_in;   // Write data to memory on rising edge of clock
        end
        if (read_enable) begin
            data_out <= memory;  // Read data from memory
        end
    end
endmodule

